const results = [];
const ts = new Date().toLocaleString('sv-SE', { timeZone: 'Asia/Shanghai' }).replace(' ', 'T') + '+08:00';

// 1. Gov tour
try {
  const govData = $('获取景区数据').first().json;
  const spot = (govData.rows || []).find(r => String(r.NAME || '').includes('田子坊'));
  if (spot && spot.NUM !== undefined && spot.NUM !== null) {
    let skip = false;
    if (spot.TIME) {
      const apiTime = new Date(spot.TIME.replace(' ', 'T') + '+08:00');
      if ((Date.now() - apiTime.getTime()) / 60000 > 30) skip = true;
    }
    if (!skip) {
      const raw = JSON.stringify({ source: 'sh_a_scenic_realtime', code: spot.CODE, name: spot.NAME, time: spot.TIME, grade: spot.GRADE, comfort: spot.SSD, max_num: spot.MAX_NUM, type: spot.TYPE, district: spot.DNAME }).replace(/'/g, "''");
      results.push({ sql: "INSERT INTO crowd_data (ts, source, metric, value, unit, confidence, raw_json) VALUES ('" + ts + "', 'gov_tour', 'in_park_count', " + Number(spot.NUM) + ", '人', 'measured', '" + raw + "')", label: 'gov_tour' });
    }
  }
} catch (e) {}

// 2. Weather - wttr.in format=j1
try {
  const wData = $('获取天气').first().json;
  const c = wData.current_condition?.[0] || {};
  const today = wData.weather?.[0] || {};
  const tempC = parseFloat(c.temp_C);
  const humidity = parseInt(c.humidity);
  const windKmph = parseFloat(c.windspeedKmph);
  const desc = c.lang_zh?.[0]?.value || c.weatherDesc?.[0]?.value || '';
  const feelsLike = parseFloat(c.FeelsLikeC);

  if (!isNaN(tempC)) {
    results.push({ sql: "INSERT INTO crowd_data (ts, source, metric, value, unit, confidence, raw_json) VALUES ('" + ts + "', 'weather', 'temperature', " + tempC + ", '℃', 'measured', '" + JSON.stringify({ feels_like: feelsLike }).replace(/'/g, "''") + "')", label: 'weather.temperature' });
  }
  if (!isNaN(humidity)) {
    results.push({ sql: "INSERT INTO crowd_data (ts, source, metric, value, unit, confidence, raw_json) VALUES ('" + ts + "', 'weather', 'humidity', " + humidity + ", '%', 'measured', '{}')", label: 'weather.humidity' });
  }
  if (!isNaN(windKmph)) {
    results.push({ sql: "INSERT INTO crowd_data (ts, source, metric, value, unit, confidence, raw_json) VALUES ('" + ts + "', 'weather', 'wind_speed', " + windKmph + ", 'km/h', 'measured', '{}')", label: 'weather.wind_speed' });
  }
  if (desc) {
    results.push({ sql: "INSERT INTO crowd_data (ts, source, metric, value, unit, confidence, raw_json) VALUES ('" + ts + "', 'weather', 'weather_desc', 0, '" + desc + "', 'measured', '{}')", label: 'weather.weather_desc' });
  }
  const maxTemp = parseFloat(today.maxtempC);
  const minTemp = parseFloat(today.mintempC);
  if (!isNaN(maxTemp)) {
    results.push({ sql: "INSERT INTO crowd_data (ts, source, metric, value, unit, confidence, raw_json) VALUES ('" + ts + "', 'weather', 'temperature_max', " + maxTemp + ", '℃', 'measured', '{}')", label: 'weather.temp_max' });
  }
  if (!isNaN(minTemp)) {
    results.push({ sql: "INSERT INTO crowd_data (ts, source, metric, value, unit, confidence, raw_json) VALUES ('" + ts + "', 'weather', 'temperature_min', " + minTemp + ", '℃', 'measured', '{}')", label: 'weather.temp_min' });
  }
} catch (e) {}

// 3. Holiday - 每天只写一次
try {
  const now = new Date();
  const month = now.toLocaleDateString('en-US', { timeZone: 'Asia/Shanghai', month: 'numeric' }) * 1;
  const day = now.toLocaleDateString('en-US', { timeZone: 'Asia/Shanghai', day: 'numeric' }) * 1;
  const weekday = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Shanghai' })).getDay();
  const wd = weekday === 0 ? 6 : weekday - 1;
  const holidays = [[1,1,'元旦'],[1,2,'元旦假期'],[1,3,'元旦假期'],[2,15,'春节假期'],[2,16,'除夕'],[2,17,'春节'],[2,18,'春节假期'],[2,19,'春节假期'],[2,20,'春节假期'],[2,21,'春节假期'],[2,22,'春节假期'],[2,23,'春节假期'],[4,4,'清明节'],[4,5,'清明假期'],[4,6,'清明假期'],[5,1,'劳动节'],[5,2,'劳动节假期'],[5,3,'劳动节假期'],[5,4,'劳动节假期'],[5,5,'劳动节假期'],[6,19,'端午节'],[6,20,'端午假期'],[6,21,'端午假期'],[9,25,'中秋节'],[9,26,'中秋假期'],[9,27,'中秋假期'],[10,1,'国庆节'],[10,2,'国庆假期'],[10,3,'国庆假期'],[10,4,'国庆假期'],[10,5,'国庆假期'],[10,6,'国庆假期'],[10,7,'国庆假期']];
  const workdays = [[1,4,'元旦调休上班'],[2,14,'春节调休上班'],[2,28,'春节调休上班'],[5,9,'劳动节调休上班'],[9,20,'国庆调休上班'],[10,10,'国庆调休上班']];
  let isHoliday = 0, holidayName = '';
  for (const [m, d, n] of holidays) { if (m === month && d === day) { isHoliday = 1; holidayName = n; break; } }
  let isWorkdayOverride = false;
  for (const [m, d, n] of workdays) { if (m === month && d === day) { isWorkdayOverride = true; holidayName = n; break; } }
  const isWorkday = (wd < 5 && !isHoliday) || isWorkdayOverride ? 1 : 0;
  const hRecords = [
    ['is_holiday', isHoliday, 'bool', 'measured', JSON.stringify({ holiday_name: holidayName }).replace(/'/g, "''")],
    ['is_workday', isWorkday, 'bool', 'measured', JSON.stringify({ weekday: wd, override: isWorkdayOverride }).replace(/'/g, "''")],
    ['weekday', wd, 'day', 'measured', '{}']
  ];
  for (const [metric, value, unit, conf, raw] of hRecords) {
    results.push({ sql: "INSERT INTO crowd_data (ts, source, metric, value, unit, confidence, raw_json) VALUES ('" + ts + "', 'holiday', '" + metric + "', " + value + ", '" + unit + "', '" + conf + "', '" + raw + "')", label: 'holiday.' + metric });
  }
} catch (e) {}

return results.map(r => ({ json: r }));
